  <polyline class="f-none s-accent"  stroke-width="1.8" points="501,165 504,160 508,158 511,160 515,165 518,170 521,172 525,170 528,165 532,160 535,158 538,160 542,165 545,170 549,172 552,170 555,165 559,160 562,158 566,160 569,165"/>
